import React, { useState, useRef, useEffect } from 'react';
import ReactDOM from 'react-dom';
import { Member, LabelType, FilterState } from '../../../types';

interface FilterBarProps {
  filter: FilterState;
  members: Member[];
  onFilterChange: (f: Partial<FilterState>) => void;
  onClear: () => void;
}

const LABELS: LabelType[] = ['Feature', 'Bug', 'Issue', 'Undefined'];
const DUE_OPTIONS = [
  { value: 'overdue', label: 'Overdue' },
  { value: 'today',   label: 'Due Today' },
  { value: 'week',    label: 'This Week' },
];

// ── SVG Icons ──────────────────────────────────────────
const IconUser = () => (
  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/>
  </svg>
);
const IconTag = () => (
  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M20.59 13.41l-7.17 7.17a2 2 0 01-2.83 0L2 12V2h10l8.59 8.59a2 2 0 010 2.82z"/><circle cx="7" cy="7" r="1.5" fill="currentColor"/>
  </svg>
);
const IconCalendar = () => (
  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
  </svg>
);
const IconChevronDown = () => (
  <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
    <polyline points="6 9 12 15 18 9"/>
  </svg>
);
const IconX = () => (
  <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
    <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
  </svg>
);
const IconFilter = () => (
  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"/>
  </svg>
);

interface PortalDropdownProps {
  anchorRef: React.RefObject<HTMLElement>;
  open: boolean;
  onClose: () => void;
  children: React.ReactNode;
  minWidth?: number;
}

const PortalDropdown: React.FC<PortalDropdownProps> = ({
  anchorRef, open, onClose, children, minWidth = 180,
}) => {
  const [coords, setCoords] = useState({ top: 0, left: 0, width: 0 });

  // Recalculate position whenever it opens
  useEffect(() => {
    if (!open || !anchorRef.current) return;
    const rect = anchorRef.current.getBoundingClientRect();
    setCoords({
      top:   rect.bottom + 6,
      left:  rect.left,
      width: rect.width,
    });
  }, [open, anchorRef]);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (!anchorRef.current?.contains(e.target as Node)) onClose();
    };
    // slight delay so the button click that opens it doesn't immediately close it
    const id = setTimeout(() => document.addEventListener('mousedown', handler), 10);
    return () => {
      clearTimeout(id);
      document.removeEventListener('mousedown', handler);
    };
  }, [open, onClose, anchorRef]);

  if (!open) return null;

  const style: React.CSSProperties = {
    position: 'fixed',
    top:      coords.top,
    left:     coords.left,
    minWidth: Math.max(minWidth, coords.width),
    zIndex:   9999,
    background:    'var(--kb-surface)',
    border:        '1px solid var(--kb-border)',
    borderRadius:  'var(--r-lg)',
    boxShadow:     'var(--kb-shadow-lg)',
    overflow:      'hidden',
    animation:     'dropdownIn 0.15s cubic-bezier(0.34,1.4,0.64,1)',
  };

  return ReactDOM.createPortal(
    <div style={style}>{children}</div>,
    document.body,
  );
};

export const FilterBar: React.FC<FilterBarProps> = ({ filter, members, onFilterChange, onClear }) => {
  const [showAssignee, setShowAssignee] = useState(false);
  const [showLabel,    setShowLabel]    = useState(false);
  const [showDue,      setShowDue]      = useState(false);
  const assigneeRef = useRef<HTMLDivElement>(null);
  const labelRef    = useRef<HTMLDivElement>(null);
  const dueRef      = useRef<HTMLDivElement>(null);

  // close all dropdowns on outside click
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (!assigneeRef.current?.contains(e.target as Node)) setShowAssignee(false);
      if (!labelRef.current?.contains(e.target as Node))    setShowLabel(false);
      if (!dueRef.current?.contains(e.target as Node))      setShowDue(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const hasFilter = filter.assigneeId || filter.label || filter.dueDate;
  const activeAssigneeName = filter.assigneeId
    ? members.find((m) => m.id === filter.assigneeId)?.name
    : null;
  const activeDueLabel = DUE_OPTIONS.find((d) => d.value === filter.dueDate)?.label ?? null;

  return (
    <div className="kb-filter-bar" >
      {/* Filter icon label */}
      <span className="kb-filter-bar__label">
        <IconFilter />
        Filter
      </span>

      <span className="kb-filter-bar__sep" />

      {/* ── Assignee ── */}
      <div className="kb-dropdown" ref={assigneeRef}>
        <button
          className={`kb-filter-chip ${filter.assigneeId ? 'active' : ''}`}
          onClick={() => { setShowAssignee(v => !v); setShowLabel(false); setShowDue(false); }}
        >
          <IconUser />
          {activeAssigneeName ?? 'Assignee'}
          {!filter.assigneeId && <IconChevronDown />}
          {filter.assigneeId && (
            <span className="kb-filter-chip__clear" onClick={(e) => { e.stopPropagation(); onFilterChange({ assigneeId: null }); }}>
              <IconX />
            </span>
          )}
        </button>

       <PortalDropdown
  anchorRef={assigneeRef}
  open={showAssignee}
  onClose={() => setShowAssignee(false)}
  minWidth={190}
>
  <div className="kb-dropdown__header">Assign to</div>

  <button
    className={`kb-dropdown__item ${!filter.assigneeId ? 'kb-dropdown__item--checked' : ''}`}
    onClick={() => {
      onFilterChange({ assigneeId: null });
      setShowAssignee(false);
    }}
  >
    <span className="kb-dropdown__item-check">
      {!filter.assigneeId && <CheckIcon />}
    </span>
    All Members
  </button>

  {members.map((m) => (
    <button
      key={m.id}
      className={`kb-dropdown__item ${filter.assigneeId === m.id ? 'kb-dropdown__item--checked' : ''}`}
      onClick={() => {
        onFilterChange({ assigneeId: m.id });
        setShowAssignee(false);
      }}
    >
      <span className="kb-dropdown__item-check">
        {filter.assigneeId === m.id && <CheckIcon />}
      </span>
      {m.name}
    </button>
  ))}
</PortalDropdown>
      </div>

      {/* ── Label ── */}
      <div className="kb-dropdown" ref={labelRef}>
        <button
          className={`kb-filter-chip ${filter.label ? 'active' : ''}`}
          onClick={() => { setShowLabel(v => !v); setShowAssignee(false); setShowDue(false); }}
        >
          <IconTag />
          {filter.label ?? 'Label'}
          {!filter.label && <IconChevronDown />}
          {filter.label && (
            <span className="kb-filter-chip__clear" onClick={(e) => { e.stopPropagation(); onFilterChange({ label: null }); }}>
              <IconX />
            </span>
          )}
        </button>
        {showLabel && (
          <div className="kb-dropdown__menu">
            <div className="kb-dropdown__header">Filter by label</div>
            <button
              className={`kb-dropdown__item ${!filter.label ? 'kb-dropdown__item--checked' : ''}`}
              onClick={() => { onFilterChange({ label: null }); setShowLabel(false); }}
            >
              <span className="kb-dropdown__item-check">{!filter.label && <CheckIcon />}</span>
              All Labels
            </button>
            {LABELS.map((l) => (
              <button
                key={l}
                className={`kb-dropdown__item ${filter.label === l ? 'kb-dropdown__item--checked' : ''}`}
                onClick={() => { onFilterChange({ label: l }); setShowLabel(false); }}
              >
                <span className="kb-dropdown__item-check">{filter.label === l && <CheckIcon />}</span>
                <span className={`kb-label-dot kb-label-dot--${l}`} />
                {l}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* ── Due Date ── */}
      <div className="kb-dropdown" ref={dueRef}>
        <button
          className={`kb-filter-chip ${filter.dueDate ? 'active' : ''}`}
          onClick={() => { setShowDue(v => !v); setShowAssignee(false); setShowLabel(false); }}
        >
          <IconCalendar />
          {activeDueLabel ?? 'Due Date'}
          {!filter.dueDate && <IconChevronDown />}
          {filter.dueDate && (
            <span className="kb-filter-chip__clear" onClick={(e) => { e.stopPropagation(); onFilterChange({ dueDate: null }); }}>
              <IconX />
            </span>
          )}
        </button>
        {showDue && (
          <div className="kb-dropdown__menu">
            <div className="kb-dropdown__header">Filter by due date</div>
            <button
              className={`kb-dropdown__item ${!filter.dueDate ? 'kb-dropdown__item--checked' : ''}`}
              onClick={() => { onFilterChange({ dueDate: null }); setShowDue(false); }}
            >
              <span className="kb-dropdown__item-check">{!filter.dueDate && <CheckIcon />}</span>
              Any Date
            </button>
            {DUE_OPTIONS.map((d) => (
              <button
                key={d.value}
                className={`kb-dropdown__item ${filter.dueDate === d.value ? 'kb-dropdown__item--checked' : ''}`}
                onClick={() => { onFilterChange({ dueDate: d.value as any }); setShowDue(false); }}
              >
                <span className="kb-dropdown__item-check">{filter.dueDate === d.value && <CheckIcon />}</span>
                {d.label}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* ── Clear all ── */}
      {hasFilter && (
        <button className="kb-filter-chip active-clear" onClick={onClear}>
          <IconX />
          Clear Filters
        </button>
      )}
    </div>
  );
};

const CheckIcon = () => (
  <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round">
    <polyline points="20 6 9 17 4 12"/>
  </svg>
);
